function updatePackageJson() {
  const file = resolve("package.json");
  const pkg = JSON.parse(fs.readFileSync(file, "utf8"));
  if (!pkg.scripts.check.includes("npm run check:p12:co5")) {
    pkg.scripts.check = pkg.scripts.check.replace(
      "npm run check:p12:co4",
      "npm run check:p12:co4 && npm run check:p12:co5"
    );
  }
  pkg.scripts["check:p12:co5"] = [
    "node --check src/phases/12-normalized-compiler/compiler.js",
    "node --check src/phases/12-normalized-compiler/phase12-compiler.runner.js",
    "node --check src/phases/12-normalized-compiler/phase10-downstream-compatibility.js",
    "node --check src/runtime/services/reporting/report-renderer.service.js",
    "node --check scripts/check-co-p12-05.mjs",
    "node scripts/check-co-p12-05.mjs"
  ].join(" && ");
  fs.writeFileSync(file, `${JSON.stringify(pkg, null, 2)}\n`);
}

function assertPostApply() {
  for (const relative of DELETES) {
    if (fs.existsSync(resolve(relative))) throw new Error(`CO_P12_05_LEGACY_DELETE_FAILED:${relative}`);
  }
  const pipeline = fs.readFileSync(resolve("src/runtime/services/pipeline.service.js"), "utf8");
  if (!pipeline.includes("phase12-compiler.runner.js")) throw new Error("CO_P12_05_PIPELINE_RUNNER_NOT_CUT_OVER");
  if (pipeline.includes("runCompilerPhase2G")) throw new Error("CO_P12_05_PHASE2G_COMPILER_REMAINS");
  const projection = fs.readFileSync(resolve("src/phases/12-normalized-compiler/phase12-projection-adapter.js"), "utf8");
  if (projection.includes("normalized_report_manifest: report_manifest")) throw new Error("CO_P12_05_MANIFEST_ALIAS_REMAINS");
  if (projection.includes("review_ready_section_handoff: report_handoff")) throw new Error("CO_P12_05_HANDOFF_ALIAS_REMAINS");
}

function write(relative, content) {
  const file = resolve(relative);
  fs.mkdirSync(path.dirname(file), { recursive: true });
  fs.writeFileSync(file, content.endsWith("\n") ? content : `${content}\n`);
}

function replaceExact(relative, before, after) {
  const file = resolve(relative);
  const source = fs.readFileSync(file, "utf8");
  if (!source.includes(before)) throw new Error(`CO_P12_05_EXACT_MARKER_MISSING:${relative}:${before.slice(0, 120)}`);
  fs.writeFileSync(file, source.split(before).join(after));
}

function replaceRegex(relative, pattern, replacement) {
  const file = resolve(relative);
  const source = fs.readFileSync(file, "utf8");
  if (!pattern.test(source)) throw new Error(`CO_P12_05_REGEX_MARKER_MISSING:${relative}:${pattern}`);
  pattern.lastIndex = 0;
  fs.writeFileSync(file, source.replace(pattern, replacement));
}

function resolve(relative) { return path.join(ROOT, relative); }
